package com.example.consulta;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.cloud.client.discovery.EnableDiscoveryClient;
import org.springframework.cloud.openfeign.EnableFeignClients;

@SpringBootApplication
@EnableDiscoveryClient
@EnableFeignClients
public class ConsultaServiceApplication {

    public static void main(String[] args) {
        SpringApplication.run(ConsultaServiceApplication.class, args);
    }
}

package com.example.consulta.client;

import com.example.consulta.dto.BeneficiarioView;
import org.springframework.cloud.openfeign.FeignClient;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;

import java.util.List;

@FeignClient(name = "beneficiarios-service", path = "/api/v1/beneficiarios")
public interface BeneficiariosClient {

    @GetMapping
    List<BeneficiarioView> listarTodos();

    @GetMapping("/{id}")
    BeneficiarioView buscarPorId(@PathVariable("id") Long id);

    @GetMapping("/cpf/{cpf}")
    BeneficiarioView buscarPorCpf(@PathVariable("cpf") String cpf);
}

package com.example.consulta.controller;

import com.example.consulta.dto.BeneficiarioView;
import com.example.consulta.service.BeneficiarioConsultaService;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.tags.Tag;
import lombok.RequiredArgsConstructor;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;

@RestController
@RequestMapping("/api/v1/consultas/beneficiarios")
@RequiredArgsConstructor
@Tag(name = "Consultas", description = "Consultas consolidadas de beneficiários")
public class ConsultaBeneficiarioController {

    private final BeneficiarioConsultaService consultaService;

    @GetMapping
    @Operation(summary = "Listar beneficiários", description = "Consulta todos os beneficiários via serviço remoto")
    public ResponseEntity<List<BeneficiarioView>> listarTodos() {
        return ResponseEntity.ok(consultaService.listarTodos());
    }

    @GetMapping("/{id}")
    @Operation(summary = "Consultar por ID", description = "Buscar beneficiário específico por ID")
    public ResponseEntity<BeneficiarioView> buscarPorId(@PathVariable Long id) {
        return consultaService.buscarPorId(id)
                .map(ResponseEntity::ok)
                .orElseGet(() -> ResponseEntity.notFound().build());
    }

    @GetMapping("/cpf/{cpf}")
    @Operation(summary = "Consultar por CPF", description = "Buscar beneficiário específico por CPF")
    public ResponseEntity<BeneficiarioView> buscarPorCpf(@PathVariable String cpf) {
        return consultaService.buscarPorCpf(cpf)
                .map(ResponseEntity::ok)
                .orElseGet(() -> ResponseEntity.notFound().build());
    }
}

package com.example.consulta.dto;

import java.time.LocalDate;

public record BeneficiarioView(
        Long id,
        String nome,
        String cpf,
        LocalDate dataNascimento,
        String situacao,
        LocalDate dataCriacao,
        LocalDate dataAtualizacao
) {
}

package com.example.consulta.service;

import com.example.consulta.client.BeneficiariosClient;
import com.example.consulta.dto.BeneficiarioView;
import feign.FeignException;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;

import java.util.List;
import java.util.Optional;

@Service
@RequiredArgsConstructor
public class BeneficiarioConsultaService {

    private final BeneficiariosClient beneficiariosClient;

    public List<BeneficiarioView> listarTodos() {
        return beneficiariosClient.listarTodos();
    }

    public Optional<BeneficiarioView> buscarPorId(Long id) {
        try {
            return Optional.ofNullable(beneficiariosClient.buscarPorId(id));
        } catch (FeignException.NotFound ex) {
            return Optional.empty();
        }
    }

    public Optional<BeneficiarioView> buscarPorCpf(String cpf) {
        try {
            return Optional.ofNullable(beneficiariosClient.buscarPorCpf(cpf));
        } catch (FeignException.NotFound ex) {
            return Optional.empty();
        }
    }
}

